CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ===========================================
-- SCHEMA (DDL)
-- ===========================================

DROP TABLE IF EXISTS public.negocios CASCADE;
CREATE TABLE public.negocios (
  id uuid DEFAULT uuid_generate_v4() NOT NULL,
  nombre text NOT NULL,
  created_at timestamp with time zone DEFAULT now(),
  stripe_customer_id text
);

DROP TABLE IF EXISTS public.planes CASCADE;
CREATE TABLE public.planes (
  id serial NOT NULL,
  codigo text NOT NULL,
  nombre text NOT NULL,
  precio_mxn numeric NOT NULL,
  limite_sucursales integer NOT NULL,
  limite_empleados_por_sucursal integer,
  descripcion text,
  activo boolean DEFAULT true
);

DROP TABLE IF EXISTS public.sucursales CASCADE;
CREATE TABLE public.sucursales (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  negocio_id uuid,
  nombre text NOT NULL,
  direccion text,
  created_at timestamp with time zone DEFAULT now(),
  cuenta_email text,
  cuenta_password text,
  telefono character varying(20),
  stripe_account_id text,
  stripe_onboarding_complete boolean DEFAULT false,
  imagen_url text,
  hora_apertura time without time zone DEFAULT '09:00:00'::time without time zone,
  hora_cierre time without time zone DEFAULT '20:00:00'::time without time zone,
  descanso_inicio time without time zone,
  descanso_fin time without time zone,
  dias_abiertos _int4 DEFAULT ARRAY[1, 2, 3, 4, 5, 6]
);

DROP TABLE IF EXISTS public.usuarios_perfiles CASCADE;
CREATE TABLE public.usuarios_perfiles (
  id uuid NOT NULL,
  nombre text,
  avatar_url text,
  rol text DEFAULT 'dueño'::text,
  negocio_id uuid,
  created_at timestamp with time zone DEFAULT now(),
  sucursal_id bigint,
  email text
);

DROP TABLE IF EXISTS public.empleados CASCADE;
CREATE TABLE public.empleados (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  negocio_id uuid,
  sucursal_id bigint,
  nombre text NOT NULL,
  especialidad text,
  created_at timestamp with time zone DEFAULT now(),
  rol text,
  imagen_url text,
  disponible boolean DEFAULT true NOT NULL
);

DROP TABLE IF EXISTS public.servicios CASCADE;
CREATE TABLE public.servicios (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  negocio_id uuid,
  sucursal_id bigint,
  nombre text NOT NULL,
  descripcion text,
  precio_base numeric DEFAULT 0,
  duracion_aprox_minutos integer DEFAULT 30,
  created_at timestamp with time zone DEFAULT now(),
  imagen_url text,
  link_pago text
);

DROP TABLE IF EXISTS public.clientes_bot CASCADE;
CREATE TABLE public.clientes_bot (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  negocio_id uuid,
  nombre text,
  telefono text,
  chat_id text,
  plataforma text DEFAULT 'manual'::text,
  created_at timestamp with time zone DEFAULT now(),
  sucursal_id bigint,
  email text
);

DROP TABLE IF EXISTS public.negocio_suscripciones CASCADE;
CREATE TABLE public.negocio_suscripciones (
  negocio_id uuid NOT NULL,
  plan_id integer,
  estado text DEFAULT 'trial'::text NOT NULL,
  fecha_fin_prueba timestamp with time zone,
  fecha_fin_periodo timestamp with time zone,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  stripe_subscription_id text,
  tipo_chatbot character varying(10) DEFAULT 'web'::character varying
);

DROP TABLE IF EXISTS public.citas CASCADE;
CREATE TABLE public.citas (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  negocio_id uuid,
  sucursal_id bigint,
  empleado_id bigint,
  cliente_id bigint,
  nombre_cliente_manual text,
  fecha_hora_inicio timestamp with time zone,
  fecha_hora_fin timestamp with time zone,
  estado text DEFAULT 'confirmada'::text,
  tipo text DEFAULT 'cita'::text,
  auto_cancelada boolean DEFAULT false,
  created_at timestamp with time zone DEFAULT now(),
  telefono text,
  servicio text,
  aviso_20min boolean DEFAULT false,
  aviso_hora boolean DEFAULT false,
  total_pagado numeric DEFAULT 0,
  fecha_completado timestamp with time zone,
  descripcion text,
  fotos_referencia _text,
  estado_pago text DEFAULT 'pendiente'::text,
  stripe_payment_intent_id text,
  stripe_session_id text,
  monto_total numeric,
  cliente_email text
);

DROP TABLE IF EXISTS public.citas_servicios CASCADE;
CREATE TABLE public.citas_servicios (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  cita_id bigint,
  servicio_id bigint,
  precio_actual numeric DEFAULT 0
);

DROP TABLE IF EXISTS public.empleado_servicios CASCADE;
CREATE TABLE public.empleado_servicios (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  empleado_id bigint,
  servicio_id bigint
);

DROP TABLE IF EXISTS public.horarios_sucursal CASCADE;
CREATE TABLE public.horarios_sucursal (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  sucursal_id bigint,
  dia_semana integer,
  hora_inicio time without time zone,
  hora_fin time without time zone,
  created_at timestamp with time zone DEFAULT now(),
  activo boolean DEFAULT true,
  hora_descanso_inicio time without time zone,
  duracion_descanso_minutos integer DEFAULT 0
);

DROP TABLE IF EXISTS public.chat_histories CASCADE;
CREATE TABLE public.chat_histories (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  session_id text,
  message jsonb,
  created_at timestamp with time zone DEFAULT now()
);

DROP TABLE IF EXISTS public.chat_actividad CASCADE;
CREATE TABLE public.chat_actividad (
  chat_id text NOT NULL,
  ultimo_mensaje timestamp with time zone
);

DROP TABLE IF EXISTS public.inbox_telegram CASCADE;
CREATE TABLE public.inbox_telegram (
  id bigint GENERATED BY DEFAULT AS IDENTITY,
  chat_id text,
  message_text text,
  message_id text,
  created_at timestamp with time zone DEFAULT now()
);

DROP TABLE IF EXISTS public.bot_sessions CASCADE;
CREATE TABLE public.bot_sessions (
  id uuid DEFAULT uuid_generate_v4() NOT NULL,
  phone_number text NOT NULL,
  current_step text NOT NULL,
  data jsonb DEFAULT '{}'::jsonb,
  updated_at timestamp with time zone DEFAULT now()
);

DROP TABLE IF EXISTS public.n8n_chat_histories CASCADE;
CREATE TABLE public.n8n_chat_histories (
  id serial NOT NULL,
  session_id text NOT NULL,
  message jsonb NOT NULL,
  createdAt timestamp with time zone DEFAULT now()
);

-- PRIMARY KEYS
